"""Ensemble methods: Random Forest, Gradient Boosting, AdaBoost, Bagging,
Extra Trees, Histogram Gradient Boosting, Isolation Forest, Voting, Stacking."""
import numpy as np
from sklearn.base import BaseEstimator, ClassifierMixin, RegressorMixin, clone
from sklearn.tree import DecisionTreeClassifier, DecisionTreeRegressor


class RandomForestClassifier(BaseEstimator, ClassifierMixin):
    def __init__(self, n_estimators=100, *, criterion='gini', max_depth=10,
                 min_samples_split=2, min_samples_leaf=1,
                 min_weight_fraction_leaf=0.0, max_features='sqrt',
                 max_leaf_nodes=None, min_impurity_decrease=0.0,
                 bootstrap=True, oob_score=False, n_jobs=None,
                 random_state=None, verbose=0, warm_start=False,
                 class_weight=None, ccp_alpha=0.0, max_samples=None,
                 monotonic_cst=None):
        self.n_estimators = n_estimators
        self.criterion = criterion
        self.max_depth = max_depth
        self.min_samples_split = min_samples_split
        self.min_samples_leaf = min_samples_leaf
        self.min_weight_fraction_leaf = min_weight_fraction_leaf
        self.max_features = max_features
        self.max_leaf_nodes = max_leaf_nodes
        self.min_impurity_decrease = min_impurity_decrease
        self.bootstrap = bootstrap
        self.oob_score = oob_score
        self.n_jobs = n_jobs
        self.random_state = random_state
        self.verbose = verbose
        self.warm_start = warm_start
        self.class_weight = class_weight
        self.ccp_alpha = ccp_alpha
        self.max_samples = max_samples
        self.monotonic_cst = monotonic_cst
        self.estimators_ = []
        self.classes_ = None

    def _get_max_features(self, n_features):
        if self.max_features == 'sqrt':
            return max(1, int(np.sqrt(n_features)))
        elif self.max_features == 'log2':
            return max(1, int(np.log2(n_features)))
        elif isinstance(self.max_features, int):
            return self.max_features
        elif isinstance(self.max_features, float):
            return max(1, int(self.max_features * n_features))
        return n_features

    def fit(self, X, y):
        X, y = np.asarray(X, dtype=float), np.asarray(y)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        self.classes_ = np.unique(y)
        rng = np.random.RandomState(self.random_state)
        n_samples, n_features = X.shape
        max_feat = self._get_max_features(n_features)
        self.estimators_ = []
        self.feature_indices_ = []
        for i in range(self.n_estimators):
            idx = rng.randint(0, n_samples, n_samples)
            feat_idx = rng.choice(n_features, max_feat, replace=False)
            feat_idx.sort()
            tree = DecisionTreeClassifier(
                max_depth=self.max_depth,
                min_samples_split=self.min_samples_split
            )
            tree.fit(X[np.ix_(idx, feat_idx)], y[idx])
            self.estimators_.append(tree)
            self.feature_indices_.append(feat_idx)
        return self

    def predict(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        predictions = np.array([
            tree.predict(X[:, feat_idx])
            for tree, feat_idx in zip(self.estimators_, self.feature_indices_)
        ])
        # Majority vote
        result = np.empty(X.shape[0], dtype=self.classes_.dtype)
        for i in range(X.shape[0]):
            vals, counts = np.unique(predictions[:, i], return_counts=True)
            result[i] = vals[np.argmax(counts)]
        return result


class RandomForestRegressor(BaseEstimator, RegressorMixin):
    def __init__(self, n_estimators=100, *, criterion='squared_error',
                 max_depth=10, min_samples_split=2, min_samples_leaf=1,
                 min_weight_fraction_leaf=0.0, max_features=1.0,
                 max_leaf_nodes=None, min_impurity_decrease=0.0,
                 bootstrap=True, oob_score=False, n_jobs=None,
                 random_state=None, verbose=0, warm_start=False,
                 ccp_alpha=0.0, max_samples=None, monotonic_cst=None):
        self.n_estimators = n_estimators
        self.criterion = criterion
        self.max_depth = max_depth
        self.min_samples_split = min_samples_split
        self.min_samples_leaf = min_samples_leaf
        self.min_weight_fraction_leaf = min_weight_fraction_leaf
        self.max_features = max_features
        self.max_leaf_nodes = max_leaf_nodes
        self.min_impurity_decrease = min_impurity_decrease
        self.bootstrap = bootstrap
        self.oob_score = oob_score
        self.n_jobs = n_jobs
        self.random_state = random_state
        self.verbose = verbose
        self.warm_start = warm_start
        self.ccp_alpha = ccp_alpha
        self.max_samples = max_samples
        self.monotonic_cst = monotonic_cst
        self.estimators_ = []

    def _get_max_features(self, n_features):
        if self.max_features == 'sqrt':
            return max(1, int(np.sqrt(n_features)))
        elif self.max_features == 'log2':
            return max(1, int(np.log2(n_features)))
        elif isinstance(self.max_features, int):
            return self.max_features
        elif isinstance(self.max_features, float):
            return max(1, int(self.max_features * n_features))
        return n_features

    def fit(self, X, y):
        X, y = np.asarray(X, dtype=float), np.asarray(y, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        rng = np.random.RandomState(self.random_state)
        n_samples, n_features = X.shape
        max_feat = self._get_max_features(n_features)
        self.estimators_ = []
        self.feature_indices_ = []
        for i in range(self.n_estimators):
            idx = rng.randint(0, n_samples, n_samples)
            feat_idx = rng.choice(n_features, max_feat, replace=False)
            feat_idx.sort()
            tree = DecisionTreeRegressor(
                max_depth=self.max_depth,
                min_samples_split=self.min_samples_split
            )
            tree.fit(X[np.ix_(idx, feat_idx)], y[idx])
            self.estimators_.append(tree)
            self.feature_indices_.append(feat_idx)
        return self

    def predict(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        predictions = np.array([
            tree.predict(X[:, feat_idx])
            for tree, feat_idx in zip(self.estimators_, self.feature_indices_)
        ])
        return np.mean(predictions, axis=0)


class GradientBoostingClassifier(BaseEstimator, ClassifierMixin):
    """Binary and multiclass gradient boosting classifier using log-loss."""

    def __init__(self, *, loss='log_loss', learning_rate=0.1, n_estimators=100,
                 subsample=1.0, criterion='friedman_mse', min_samples_split=2,
                 min_samples_leaf=1, min_weight_fraction_leaf=0.0,
                 max_depth=3, min_impurity_decrease=0.0, init=None,
                 random_state=None, max_features=None, verbose=0,
                 max_leaf_nodes=None, warm_start=False, validation_fraction=0.1,
                 n_iter_no_change=None, tol=1e-4, ccp_alpha=0.0):
        self.loss = loss
        self.learning_rate = learning_rate
        self.n_estimators = n_estimators
        self.subsample = subsample
        self.criterion = criterion
        self.min_samples_split = min_samples_split
        self.min_samples_leaf = min_samples_leaf
        self.min_weight_fraction_leaf = min_weight_fraction_leaf
        self.max_depth = max_depth
        self.min_impurity_decrease = min_impurity_decrease
        self.init = init
        self.random_state = random_state
        self.max_features = max_features
        self.verbose = verbose
        self.max_leaf_nodes = max_leaf_nodes
        self.warm_start = warm_start
        self.validation_fraction = validation_fraction
        self.n_iter_no_change = n_iter_no_change
        self.tol = tol
        self.ccp_alpha = ccp_alpha
        self.estimators_ = []
        self.classes_ = None

    @staticmethod
    def _sigmoid(x):
        x = np.clip(x, -500, 500)
        return 1.0 / (1.0 + np.exp(-x))

    @staticmethod
    def _softmax(x):
        x = x - np.max(x, axis=1, keepdims=True)
        e = np.exp(x)
        return e / e.sum(axis=1, keepdims=True)

    def fit(self, X, y):
        X, y = np.asarray(X, dtype=float), np.asarray(y)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        self.classes_ = np.unique(y)
        n_classes = len(self.classes_)

        if n_classes == 2:
            # Binary: single output
            y_bin = (y == self.classes_[1]).astype(float)
            p = np.mean(y_bin)
            self.init_pred_ = np.log(max(p, 1e-15) / max(1 - p, 1e-15))
            F = np.full(len(X), self.init_pred_)
            self.estimators_ = []
            for _ in range(self.n_estimators):
                prob = self._sigmoid(F)
                residual = y_bin - prob
                tree = DecisionTreeRegressor(
                    max_depth=self.max_depth,
                    min_samples_split=self.min_samples_split
                )
                tree.fit(X, residual)
                F += self.learning_rate * tree.predict(X)
                self.estimators_.append(tree)
        else:
            # Multiclass: one tree per class per iteration
            label_matrix = np.zeros((len(y), n_classes))
            for k, c in enumerate(self.classes_):
                label_matrix[:, k] = (y == c).astype(float)
            prior = label_matrix.mean(axis=0)
            prior = np.clip(prior, 1e-15, 1 - 1e-15)
            self.init_pred_ = np.log(prior)
            F = np.tile(self.init_pred_, (len(X), 1))
            self.estimators_ = []
            for _ in range(self.n_estimators):
                prob = self._softmax(F)
                trees_round = []
                for k in range(n_classes):
                    residual = label_matrix[:, k] - prob[:, k]
                    tree = DecisionTreeRegressor(
                        max_depth=self.max_depth,
                        min_samples_split=self.min_samples_split
                    )
                    tree.fit(X, residual)
                    F[:, k] += self.learning_rate * tree.predict(X)
                    trees_round.append(tree)
                self.estimators_.append(trees_round)
        return self

    def predict(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        n_classes = len(self.classes_)
        if n_classes == 2:
            F = np.full(len(X), self.init_pred_)
            for tree in self.estimators_:
                F += self.learning_rate * tree.predict(X)
            prob = self._sigmoid(F)
            indices = (prob >= 0.5).astype(int)
            return self.classes_[indices]
        else:
            F = np.tile(self.init_pred_, (len(X), 1))
            for trees_round in self.estimators_:
                for k, tree in enumerate(trees_round):
                    F[:, k] += self.learning_rate * tree.predict(X)
            return self.classes_[np.argmax(F, axis=1)]


class GradientBoostingRegressor(BaseEstimator, RegressorMixin):
    def __init__(self, *, loss='squared_error', learning_rate=0.1,
                 n_estimators=100, subsample=1.0, criterion='friedman_mse',
                 min_samples_split=2, min_samples_leaf=1,
                 min_weight_fraction_leaf=0.0, max_depth=3,
                 min_impurity_decrease=0.0, init=None, random_state=None,
                 max_features=None, alpha=0.9, verbose=0,
                 max_leaf_nodes=None, warm_start=False,
                 validation_fraction=0.1, n_iter_no_change=None,
                 tol=1e-4, ccp_alpha=0.0):
        self.loss = loss
        self.learning_rate = learning_rate
        self.n_estimators = n_estimators
        self.subsample = subsample
        self.criterion = criterion
        self.min_samples_split = min_samples_split
        self.min_samples_leaf = min_samples_leaf
        self.min_weight_fraction_leaf = min_weight_fraction_leaf
        self.max_depth = max_depth
        self.min_impurity_decrease = min_impurity_decrease
        self.init = init
        self.random_state = random_state
        self.max_features = max_features
        self.alpha = alpha
        self.verbose = verbose
        self.max_leaf_nodes = max_leaf_nodes
        self.warm_start = warm_start
        self.validation_fraction = validation_fraction
        self.n_iter_no_change = n_iter_no_change
        self.tol = tol
        self.ccp_alpha = ccp_alpha
        self.estimators_ = []
        self.init_pred_ = None

    def fit(self, X, y):
        X, y = np.asarray(X, dtype=float), np.asarray(y, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        self.init_pred_ = np.mean(y)
        F = np.full(len(X), self.init_pred_)
        self.estimators_ = []
        for _ in range(self.n_estimators):
            residual = y - F
            tree = DecisionTreeRegressor(
                max_depth=self.max_depth,
                min_samples_split=self.min_samples_split
            )
            tree.fit(X, residual)
            F += self.learning_rate * tree.predict(X)
            self.estimators_.append(tree)
        return self

    def predict(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        F = np.full(len(X), self.init_pred_)
        for tree in self.estimators_:
            F += self.learning_rate * tree.predict(X)
        return F


class AdaBoostClassifier(BaseEstimator, ClassifierMixin):
    def __init__(self, estimator=None, *, n_estimators=50, learning_rate=1.0,
                 algorithm='SAMME', random_state=None):
        self.estimator = estimator
        self.n_estimators = n_estimators
        self.learning_rate = learning_rate
        self.algorithm = algorithm
        self.random_state = random_state
        self.estimators_ = []
        self.estimator_weights_ = []
        self.classes_ = None

    def fit(self, X, y):
        X, y = np.asarray(X, dtype=float), np.asarray(y)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        self.classes_ = np.unique(y)
        n_samples = len(X)
        w = np.full(n_samples, 1.0 / n_samples)
        self.estimators_ = []
        self.estimator_weights_ = []
        rng = np.random.RandomState(self.random_state)
        for _ in range(self.n_estimators):
            tree = DecisionTreeClassifier(max_depth=1, min_samples_split=2)
            # Weighted bootstrap sample
            indices = rng.choice(n_samples, n_samples, replace=True, p=w)
            tree.fit(X[indices], y[indices])
            pred = tree.predict(X)
            incorrect = (pred != y)
            err = np.sum(w * incorrect) / np.sum(w)
            err = np.clip(err, 1e-15, 1 - 1e-15)
            if err >= 0.5:
                break
            alpha = self.learning_rate * 0.5 * np.log((1 - err) / err)
            w *= np.exp(alpha * incorrect.astype(float) * 2 - alpha)
            w /= np.sum(w)
            self.estimators_.append(tree)
            self.estimator_weights_.append(alpha)
        return self

    def predict(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        if len(self.estimators_) == 0:
            return np.full(len(X), self.classes_[0])
        # Weighted vote
        n_classes = len(self.classes_)
        class_votes = np.zeros((len(X), n_classes))
        for tree, alpha in zip(self.estimators_, self.estimator_weights_):
            pred = tree.predict(X)
            for k, c in enumerate(self.classes_):
                class_votes[:, k] += alpha * (pred == c)
        return self.classes_[np.argmax(class_votes, axis=1)]


class BaggingClassifier(BaseEstimator, ClassifierMixin):
    def __init__(self, estimator=None, n_estimators=10, *, max_samples=1.0,
                 max_features=1.0, bootstrap=True, bootstrap_features=False,
                 oob_score=False, warm_start=False, n_jobs=None,
                 random_state=None, verbose=0, base_estimator=None):
        self.estimator = estimator
        self.n_estimators = n_estimators
        self.max_samples = max_samples
        self.max_features = max_features
        self.bootstrap = bootstrap
        self.bootstrap_features = bootstrap_features
        self.oob_score = oob_score
        self.warm_start = warm_start
        self.n_jobs = n_jobs
        self.random_state = random_state
        self.verbose = verbose
        self.base_estimator = base_estimator or estimator
        self.estimators_ = []
        self.classes_ = None

    def fit(self, X, y):
        X, y = np.asarray(X, dtype=float), np.asarray(y)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        self.classes_ = np.unique(y)
        rng = np.random.RandomState(self.random_state)
        n_samples = X.shape[0]
        if isinstance(self.max_samples, float):
            sample_size = max(1, int(self.max_samples * n_samples))
        else:
            sample_size = self.max_samples
        self.estimators_ = []
        for _ in range(self.n_estimators):
            idx = rng.randint(0, n_samples, sample_size)
            if self.base_estimator is not None:
                est = type(self.base_estimator)(**self.base_estimator.get_params())
            else:
                est = DecisionTreeClassifier(max_depth=10)
            est.fit(X[idx], y[idx])
            self.estimators_.append(est)
        return self

    def predict(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        predictions = np.array([est.predict(X) for est in self.estimators_])
        result = np.empty(X.shape[0], dtype=self.classes_.dtype)
        for i in range(X.shape[0]):
            vals, counts = np.unique(predictions[:, i], return_counts=True)
            result[i] = vals[np.argmax(counts)]
        return result


# ---------------------------------------------------------------------------
# AdaBoostRegressor
# ---------------------------------------------------------------------------
class AdaBoostRegressor(BaseEstimator, RegressorMixin):
    """AdaBoost regressor using weighted-median prediction (SAMME.R style)."""

    def __init__(self, estimator=None, *, n_estimators=50, learning_rate=1.0,
                 loss='linear', random_state=None):
        self.estimator = estimator
        self.n_estimators = n_estimators
        self.learning_rate = learning_rate
        self.loss = loss
        self.random_state = random_state
        self.estimators_ = []
        self.estimator_weights_ = []

    def fit(self, X, y):
        X, y = np.asarray(X, dtype=float), np.asarray(y, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        n_samples = len(X)
        w = np.full(n_samples, 1.0 / n_samples)
        rng = np.random.RandomState(self.random_state)
        self.estimators_ = []
        self.estimator_weights_ = []
        for _ in range(self.n_estimators):
            if self.estimator is not None:
                est = clone(self.estimator)
            else:
                est = DecisionTreeRegressor(max_depth=3, min_samples_split=2)
            indices = rng.choice(n_samples, n_samples, replace=True, p=w)
            est.fit(X[indices], y[indices])
            pred = est.predict(X)
            error = np.abs(pred - y)
            max_err = np.max(error)
            if max_err > 0:
                error /= max_err
            if self.loss == 'square':
                error = error ** 2
            elif self.loss == 'exponential':
                error = 1.0 - np.exp(-error)
            # else 'linear' -- keep as is
            weighted_err = np.sum(w * error)
            if weighted_err >= 0.5:
                break
            if weighted_err <= 0.0:
                self.estimators_.append(est)
                self.estimator_weights_.append(1.0)
                break
            beta = weighted_err / (1.0 - weighted_err)
            alpha = self.learning_rate * np.log(1.0 / max(beta, 1e-15))
            w *= np.power(beta, (1.0 - error))
            w /= np.sum(w)
            self.estimators_.append(est)
            self.estimator_weights_.append(alpha)
        return self

    def predict(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        if len(self.estimators_) == 0:
            return np.zeros(len(X))
        preds = np.array([est.predict(X) for est in self.estimators_])
        weights = np.array(self.estimator_weights_)
        # Weighted median for each sample
        result = np.empty(X.shape[0])
        for i in range(X.shape[0]):
            sorted_idx = np.argsort(preds[:, i])
            sorted_preds = preds[sorted_idx, i]
            sorted_weights = weights[sorted_idx]
            cum_w = np.cumsum(sorted_weights)
            median_idx = np.searchsorted(cum_w, cum_w[-1] / 2.0)
            result[i] = sorted_preds[min(median_idx, len(sorted_preds) - 1)]
        return result


# ---------------------------------------------------------------------------
# BaggingRegressor
# ---------------------------------------------------------------------------
class BaggingRegressor(BaseEstimator, RegressorMixin):
    """Bagging regressor -- averages predictions from bootstrapped estimators."""

    def __init__(self, estimator=None, n_estimators=10, *, max_samples=1.0,
                 max_features=1.0, bootstrap=True, bootstrap_features=False,
                 oob_score=False, warm_start=False, n_jobs=None,
                 random_state=None, verbose=0, base_estimator=None):
        self.estimator = estimator
        self.n_estimators = n_estimators
        self.max_samples = max_samples
        self.max_features = max_features
        self.bootstrap = bootstrap
        self.bootstrap_features = bootstrap_features
        self.oob_score = oob_score
        self.warm_start = warm_start
        self.n_jobs = n_jobs
        self.random_state = random_state
        self.verbose = verbose
        self.base_estimator = base_estimator or estimator
        self.estimators_ = []

    def fit(self, X, y):
        X, y = np.asarray(X, dtype=float), np.asarray(y, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        rng = np.random.RandomState(self.random_state)
        n_samples = X.shape[0]
        if isinstance(self.max_samples, float):
            sample_size = max(1, int(self.max_samples * n_samples))
        else:
            sample_size = self.max_samples
        self.estimators_ = []
        for _ in range(self.n_estimators):
            if self.bootstrap:
                idx = rng.randint(0, n_samples, sample_size)
            else:
                idx = rng.choice(n_samples, sample_size, replace=False)
            if self.base_estimator is not None:
                est = clone(self.base_estimator)
            else:
                est = DecisionTreeRegressor(max_depth=10)
            est.fit(X[idx], y[idx])
            self.estimators_.append(est)
        return self

    def predict(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        predictions = np.array([est.predict(X) for est in self.estimators_])
        return np.mean(predictions, axis=0)


# ---------------------------------------------------------------------------
# ExtraTreesClassifier
# ---------------------------------------------------------------------------
class ExtraTreesClassifier(BaseEstimator, ClassifierMixin):
    """Extremely Randomized Trees classifier -- random thresholds, not best."""

    def __init__(self, n_estimators=100, *, criterion='gini', max_depth=10,
                 min_samples_split=2, min_samples_leaf=1,
                 min_weight_fraction_leaf=0.0, max_features='sqrt',
                 max_leaf_nodes=None, min_impurity_decrease=0.0,
                 bootstrap=False, oob_score=False, n_jobs=None,
                 random_state=None, verbose=0, warm_start=False,
                 class_weight=None, ccp_alpha=0.0, max_samples=None,
                 monotonic_cst=None):
        self.n_estimators = n_estimators
        self.criterion = criterion
        self.max_depth = max_depth
        self.min_samples_split = min_samples_split
        self.min_samples_leaf = min_samples_leaf
        self.min_weight_fraction_leaf = min_weight_fraction_leaf
        self.max_features = max_features
        self.max_leaf_nodes = max_leaf_nodes
        self.min_impurity_decrease = min_impurity_decrease
        self.bootstrap = bootstrap
        self.oob_score = oob_score
        self.n_jobs = n_jobs
        self.random_state = random_state
        self.verbose = verbose
        self.warm_start = warm_start
        self.class_weight = class_weight
        self.ccp_alpha = ccp_alpha
        self.max_samples = max_samples
        self.monotonic_cst = monotonic_cst
        self.estimators_ = []
        self.classes_ = None

    def _get_max_features(self, n_features):
        if self.max_features == 'sqrt':
            return max(1, int(np.sqrt(n_features)))
        elif self.max_features == 'log2':
            return max(1, int(np.log2(n_features)))
        elif isinstance(self.max_features, int):
            return self.max_features
        elif isinstance(self.max_features, float):
            return max(1, int(self.max_features * n_features))
        return n_features

    def _build_extra_tree(self, X, y, max_depth, min_samples_split, rng):
        """Build a single extra-tree node using random splits."""
        n_samples, n_features = X.shape
        classes = np.unique(y)
        if len(classes) == 1 or n_samples < min_samples_split or max_depth <= 0:
            vals, counts = np.unique(y, return_counts=True)
            return {'leaf': True, 'value': vals[np.argmax(counts)]}
        max_feat = self._get_max_features(n_features)
        feat_idx = rng.choice(n_features, min(max_feat, n_features), replace=False)
        best_feat, best_thresh, best_score = None, None, np.inf
        for f in feat_idx:
            col = X[:, f]
            lo, hi = col.min(), col.max()
            if lo == hi:
                continue
            thresh = rng.uniform(lo, hi)
            left_mask = col <= thresh
            right_mask = ~left_mask
            if left_mask.sum() == 0 or right_mask.sum() == 0:
                continue
            # Gini for each side
            score = 0.0
            for mask in (left_mask, right_mask):
                sub = y[mask]
                p = np.bincount(
                    np.searchsorted(classes, sub),
                    minlength=len(classes)
                ).astype(float)
                p /= p.sum()
                score += mask.sum() * (1.0 - np.sum(p ** 2))
            if score < best_score:
                best_score = score
                best_feat = f
                best_thresh = thresh
        if best_feat is None:
            vals, counts = np.unique(y, return_counts=True)
            return {'leaf': True, 'value': vals[np.argmax(counts)]}
        left_mask = X[:, best_feat] <= best_thresh
        return {
            'leaf': False,
            'feature': best_feat,
            'threshold': best_thresh,
            'left': self._build_extra_tree(X[left_mask], y[left_mask],
                                           max_depth - 1, min_samples_split, rng),
            'right': self._build_extra_tree(X[~left_mask], y[~left_mask],
                                            max_depth - 1, min_samples_split, rng),
        }

    @staticmethod
    def _predict_tree(node, X):
        results = np.empty(len(X), dtype=object)
        for i in range(len(X)):
            n = node
            while not n['leaf']:
                if X[i, n['feature']] <= n['threshold']:
                    n = n['left']
                else:
                    n = n['right']
            results[i] = n['value']
        return results

    def fit(self, X, y):
        X, y = np.asarray(X, dtype=float), np.asarray(y)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        self.classes_ = np.unique(y)
        rng = np.random.RandomState(self.random_state)
        n_samples = X.shape[0]
        self.estimators_ = []
        for _ in range(self.n_estimators):
            if self.bootstrap:
                idx = rng.randint(0, n_samples, n_samples)
                X_sub, y_sub = X[idx], y[idx]
            else:
                X_sub, y_sub = X, y
            tree = self._build_extra_tree(X_sub, y_sub, self.max_depth,
                                          self.min_samples_split, rng)
            self.estimators_.append(tree)
        return self

    def predict(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        predictions = np.array([self._predict_tree(t, X) for t in self.estimators_])
        result = np.empty(X.shape[0], dtype=self.classes_.dtype)
        for i in range(X.shape[0]):
            vals, counts = np.unique(predictions[:, i], return_counts=True)
            result[i] = vals[np.argmax(counts)]
        return result


# ---------------------------------------------------------------------------
# ExtraTreesRegressor
# ---------------------------------------------------------------------------
class ExtraTreesRegressor(BaseEstimator, RegressorMixin):
    """Extremely Randomized Trees regressor -- random thresholds, not best."""

    def __init__(self, n_estimators=100, *, criterion='squared_error',
                 max_depth=10, min_samples_split=2, min_samples_leaf=1,
                 min_weight_fraction_leaf=0.0, max_features=1.0,
                 max_leaf_nodes=None, min_impurity_decrease=0.0,
                 bootstrap=False, oob_score=False, n_jobs=None,
                 random_state=None, verbose=0, warm_start=False,
                 ccp_alpha=0.0, max_samples=None, monotonic_cst=None):
        self.n_estimators = n_estimators
        self.criterion = criterion
        self.max_depth = max_depth
        self.min_samples_split = min_samples_split
        self.min_samples_leaf = min_samples_leaf
        self.min_weight_fraction_leaf = min_weight_fraction_leaf
        self.max_features = max_features
        self.max_leaf_nodes = max_leaf_nodes
        self.min_impurity_decrease = min_impurity_decrease
        self.bootstrap = bootstrap
        self.oob_score = oob_score
        self.n_jobs = n_jobs
        self.random_state = random_state
        self.verbose = verbose
        self.warm_start = warm_start
        self.ccp_alpha = ccp_alpha
        self.max_samples = max_samples
        self.monotonic_cst = monotonic_cst
        self.estimators_ = []

    def _get_max_features(self, n_features):
        if self.max_features == 'sqrt':
            return max(1, int(np.sqrt(n_features)))
        elif self.max_features == 'log2':
            return max(1, int(np.log2(n_features)))
        elif isinstance(self.max_features, int):
            return self.max_features
        elif isinstance(self.max_features, float):
            return max(1, int(self.max_features * n_features))
        return n_features

    def _build_extra_tree(self, X, y, max_depth, min_samples_split, rng):
        n_samples, n_features = X.shape
        if n_samples < min_samples_split or max_depth <= 0 or np.std(y) < 1e-12:
            return {'leaf': True, 'value': np.mean(y)}
        max_feat = self._get_max_features(n_features)
        feat_idx = rng.choice(n_features, min(max_feat, n_features), replace=False)
        best_feat, best_thresh, best_score = None, None, np.inf
        for f in feat_idx:
            col = X[:, f]
            lo, hi = col.min(), col.max()
            if lo == hi:
                continue
            thresh = rng.uniform(lo, hi)
            left_mask = col <= thresh
            right_mask = ~left_mask
            if left_mask.sum() == 0 or right_mask.sum() == 0:
                continue
            score = (np.var(y[left_mask]) * left_mask.sum() +
                     np.var(y[right_mask]) * right_mask.sum())
            if score < best_score:
                best_score = score
                best_feat = f
                best_thresh = thresh
        if best_feat is None:
            return {'leaf': True, 'value': np.mean(y)}
        left_mask = X[:, best_feat] <= best_thresh
        return {
            'leaf': False,
            'feature': best_feat,
            'threshold': best_thresh,
            'left': self._build_extra_tree(X[left_mask], y[left_mask],
                                           max_depth - 1, min_samples_split, rng),
            'right': self._build_extra_tree(X[~left_mask], y[~left_mask],
                                            max_depth - 1, min_samples_split, rng),
        }

    @staticmethod
    def _predict_tree(node, X):
        results = np.empty(len(X))
        for i in range(len(X)):
            n = node
            while not n['leaf']:
                if X[i, n['feature']] <= n['threshold']:
                    n = n['left']
                else:
                    n = n['right']
            results[i] = n['value']
        return results

    def fit(self, X, y):
        X, y = np.asarray(X, dtype=float), np.asarray(y, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        rng = np.random.RandomState(self.random_state)
        n_samples = X.shape[0]
        self.estimators_ = []
        for _ in range(self.n_estimators):
            if self.bootstrap:
                idx = rng.randint(0, n_samples, n_samples)
                X_sub, y_sub = X[idx], y[idx]
            else:
                X_sub, y_sub = X, y
            tree = self._build_extra_tree(X_sub, y_sub, self.max_depth,
                                          self.min_samples_split, rng)
            self.estimators_.append(tree)
        return self

    def predict(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        predictions = np.array([self._predict_tree(t, X) for t in self.estimators_])
        return np.mean(predictions, axis=0)


# ---------------------------------------------------------------------------
# HistGradientBoostingClassifier
# ---------------------------------------------------------------------------
class HistGradientBoostingClassifier(BaseEstimator, ClassifierMixin):
    """Histogram-based gradient boosting classifier.

    Bins features into up to max_bins discrete levels using np.digitize,
    then runs gradient boosting on the binned representation.
    """

    def __init__(self, loss='log_loss', *, learning_rate=0.1, max_iter=100,
                 max_leaf_nodes=31, max_depth=None, min_samples_leaf=20,
                 l2_regularization=0, max_bins=255,
                 categorical_features=None, monotonic_cst=None,
                 interaction_cst=None, warm_start=False,
                 early_stopping='auto', scoring='loss',
                 validation_fraction=0.1, n_iter_no_change=10,
                 tol=1e-7, verbose=0, random_state=None,
                 class_weight=None):
        self.loss = loss
        self.learning_rate = learning_rate
        self.max_iter = max_iter
        self.max_leaf_nodes = max_leaf_nodes
        self.max_depth = max_depth
        self.min_samples_leaf = min_samples_leaf
        self.l2_regularization = l2_regularization
        self.max_bins = max_bins
        self.categorical_features = categorical_features
        self.monotonic_cst = monotonic_cst
        self.interaction_cst = interaction_cst
        self.warm_start = warm_start
        self.early_stopping = early_stopping
        self.scoring = scoring
        self.validation_fraction = validation_fraction
        self.n_iter_no_change = n_iter_no_change
        self.tol = tol
        self.verbose = verbose
        self.random_state = random_state
        self.class_weight = class_weight
        self.classes_ = None
        self.estimators_ = []
        self.bin_edges_ = []

    @staticmethod
    def _sigmoid(x):
        x = np.clip(x, -500, 500)
        return 1.0 / (1.0 + np.exp(-x))

    @staticmethod
    def _softmax(x):
        x = x - np.max(x, axis=1, keepdims=True)
        e = np.exp(x)
        return e / e.sum(axis=1, keepdims=True)

    def _bin_features(self, X, fit=False):
        """Bin each feature into max_bins discrete levels."""
        X_binned = np.empty_like(X, dtype=np.uint8)
        if fit:
            self.bin_edges_ = []
            for j in range(X.shape[1]):
                col = X[:, j]
                n_bins = min(self.max_bins, len(np.unique(col)))
                edges = np.percentile(col, np.linspace(0, 100, n_bins + 1)[1:-1])
                edges = np.unique(edges)
                self.bin_edges_.append(edges)
                X_binned[:, j] = np.digitize(col, edges).astype(np.uint8)
        else:
            for j in range(X.shape[1]):
                X_binned[:, j] = np.digitize(X[:, j], self.bin_edges_[j]).astype(np.uint8)
        return X_binned.astype(float)

    def fit(self, X, y):
        X, y = np.asarray(X, dtype=float), np.asarray(y)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        self.classes_ = np.unique(y)
        n_classes = len(self.classes_)
        X_b = self._bin_features(X, fit=True)
        effective_depth = self.max_depth if self.max_depth is not None else 6

        if n_classes == 2:
            y_bin = (y == self.classes_[1]).astype(float)
            p = np.mean(y_bin)
            self.init_pred_ = np.log(max(p, 1e-15) / max(1 - p, 1e-15))
            F = np.full(len(X_b), self.init_pred_)
            self.estimators_ = []
            for _ in range(self.max_iter):
                prob = self._sigmoid(F)
                residual = y_bin - prob
                tree = DecisionTreeRegressor(
                    max_depth=effective_depth,
                    min_samples_leaf=self.min_samples_leaf
                )
                tree.fit(X_b, residual)
                update = tree.predict(X_b)
                if self.l2_regularization > 0:
                    update /= (1.0 + self.l2_regularization)
                F += self.learning_rate * update
                self.estimators_.append(tree)
        else:
            label_matrix = np.zeros((len(y), n_classes))
            for k, c in enumerate(self.classes_):
                label_matrix[:, k] = (y == c).astype(float)
            prior = np.clip(label_matrix.mean(axis=0), 1e-15, 1 - 1e-15)
            self.init_pred_ = np.log(prior)
            F = np.tile(self.init_pred_, (len(X_b), 1))
            self.estimators_ = []
            for _ in range(self.max_iter):
                prob = self._softmax(F)
                trees_round = []
                for k in range(n_classes):
                    residual = label_matrix[:, k] - prob[:, k]
                    tree = DecisionTreeRegressor(
                        max_depth=effective_depth,
                        min_samples_leaf=self.min_samples_leaf
                    )
                    tree.fit(X_b, residual)
                    update = tree.predict(X_b)
                    if self.l2_regularization > 0:
                        update /= (1.0 + self.l2_regularization)
                    F[:, k] += self.learning_rate * update
                    trees_round.append(tree)
                self.estimators_.append(trees_round)
        return self

    def predict(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        X_b = self._bin_features(X)
        n_classes = len(self.classes_)
        if n_classes == 2:
            F = np.full(len(X_b), self.init_pred_)
            for tree in self.estimators_:
                update = tree.predict(X_b)
                if self.l2_regularization > 0:
                    update /= (1.0 + self.l2_regularization)
                F += self.learning_rate * update
            prob = self._sigmoid(F)
            return self.classes_[(prob >= 0.5).astype(int)]
        else:
            F = np.tile(self.init_pred_, (len(X_b), 1))
            for trees_round in self.estimators_:
                for k, tree in enumerate(trees_round):
                    update = tree.predict(X_b)
                    if self.l2_regularization > 0:
                        update /= (1.0 + self.l2_regularization)
                    F[:, k] += self.learning_rate * update
            return self.classes_[np.argmax(F, axis=1)]


# ---------------------------------------------------------------------------
# HistGradientBoostingRegressor
# ---------------------------------------------------------------------------
class HistGradientBoostingRegressor(BaseEstimator, RegressorMixin):
    """Histogram-based gradient boosting regressor."""

    def __init__(self, loss='squared_error', *, learning_rate=0.1,
                 max_iter=100, max_leaf_nodes=31, max_depth=None,
                 min_samples_leaf=20, l2_regularization=0, max_bins=255,
                 categorical_features=None, monotonic_cst=None,
                 interaction_cst=None, warm_start=False,
                 early_stopping='auto', scoring='loss',
                 validation_fraction=0.1, n_iter_no_change=10,
                 tol=1e-7, verbose=0, random_state=None):
        self.loss = loss
        self.learning_rate = learning_rate
        self.max_iter = max_iter
        self.max_leaf_nodes = max_leaf_nodes
        self.max_depth = max_depth
        self.min_samples_leaf = min_samples_leaf
        self.l2_regularization = l2_regularization
        self.max_bins = max_bins
        self.categorical_features = categorical_features
        self.monotonic_cst = monotonic_cst
        self.interaction_cst = interaction_cst
        self.warm_start = warm_start
        self.early_stopping = early_stopping
        self.scoring = scoring
        self.validation_fraction = validation_fraction
        self.n_iter_no_change = n_iter_no_change
        self.tol = tol
        self.verbose = verbose
        self.random_state = random_state
        self.estimators_ = []
        self.bin_edges_ = []
        self.init_pred_ = None

    def _bin_features(self, X, fit=False):
        X_binned = np.empty_like(X, dtype=np.uint8)
        if fit:
            self.bin_edges_ = []
            for j in range(X.shape[1]):
                col = X[:, j]
                n_bins = min(self.max_bins, len(np.unique(col)))
                edges = np.percentile(col, np.linspace(0, 100, n_bins + 1)[1:-1])
                edges = np.unique(edges)
                self.bin_edges_.append(edges)
                X_binned[:, j] = np.digitize(col, edges).astype(np.uint8)
        else:
            for j in range(X.shape[1]):
                X_binned[:, j] = np.digitize(X[:, j], self.bin_edges_[j]).astype(np.uint8)
        return X_binned.astype(float)

    def fit(self, X, y):
        X, y = np.asarray(X, dtype=float), np.asarray(y, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        X_b = self._bin_features(X, fit=True)
        self.init_pred_ = np.mean(y)
        F = np.full(len(X_b), self.init_pred_)
        effective_depth = self.max_depth if self.max_depth is not None else 6
        self.estimators_ = []
        for _ in range(self.max_iter):
            residual = y - F
            tree = DecisionTreeRegressor(
                max_depth=effective_depth,
                min_samples_leaf=self.min_samples_leaf
            )
            tree.fit(X_b, residual)
            update = tree.predict(X_b)
            if self.l2_regularization > 0:
                update /= (1.0 + self.l2_regularization)
            F += self.learning_rate * update
            self.estimators_.append(tree)
        return self

    def predict(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        X_b = self._bin_features(X)
        F = np.full(len(X_b), self.init_pred_)
        for tree in self.estimators_:
            update = tree.predict(X_b)
            if self.l2_regularization > 0:
                update /= (1.0 + self.l2_regularization)
            F += self.learning_rate * update
        return F


# ---------------------------------------------------------------------------
# IsolationForest
# ---------------------------------------------------------------------------
class IsolationForest(BaseEstimator):
    """Isolation Forest for anomaly detection.

    Builds random trees with random splits; anomalies have shorter average
    path lengths.  Score: s(x) = 2^(-E[h(x)] / c(n)) where c(n) is the
    average path length of an unsuccessful search in a BST.
    """

    def __init__(self, *, n_estimators=100, max_samples='auto',
                 contamination='auto', max_features=1.0, bootstrap=False,
                 n_jobs=None, random_state=None, verbose=0,
                 warm_start=False):
        self.n_estimators = n_estimators
        self.max_samples = max_samples
        self.contamination = contamination
        self.max_features = max_features
        self.bootstrap = bootstrap
        self.n_jobs = n_jobs
        self.random_state = random_state
        self.verbose = verbose
        self.warm_start = warm_start
        self.estimators_ = []
        self.offset_ = 0.0

    @staticmethod
    def _c(n):
        """Average path length of unsuccessful search in BST."""
        if n <= 1:
            return 0.0
        h = np.log(n - 1) + 0.5772156649  # Euler-Mascheroni
        return 2.0 * h - 2.0 * (n - 1) / n

    def _build_isolation_tree(self, X, rng, depth=0, max_depth=10):
        n_samples, n_features = X.shape
        if n_samples <= 1 or depth >= max_depth:
            return {'leaf': True, 'size': n_samples}
        feat = rng.randint(0, n_features)
        col = X[:, feat]
        lo, hi = col.min(), col.max()
        if lo == hi:
            return {'leaf': True, 'size': n_samples}
        thresh = rng.uniform(lo, hi)
        left_mask = col < thresh
        right_mask = ~left_mask
        return {
            'leaf': False,
            'feature': feat,
            'threshold': thresh,
            'left': self._build_isolation_tree(X[left_mask], rng,
                                               depth + 1, max_depth),
            'right': self._build_isolation_tree(X[right_mask], rng,
                                                depth + 1, max_depth),
        }

    def _path_length(self, x, node, depth=0):
        """Compute path length for a single sample."""
        if node['leaf']:
            return depth + self._c(node['size'])
        if x[node['feature']] < node['threshold']:
            return self._path_length(x, node['left'], depth + 1)
        else:
            return self._path_length(x, node['right'], depth + 1)

    def fit(self, X, y=None):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        n_samples = X.shape[0]
        if self.max_samples == 'auto':
            sample_size = min(256, n_samples)
        elif isinstance(self.max_samples, float):
            sample_size = max(1, int(self.max_samples * n_samples))
        else:
            sample_size = self.max_samples
        max_depth = int(np.ceil(np.log2(max(sample_size, 2))))
        rng = np.random.RandomState(self.random_state)
        self.estimators_ = []
        for _ in range(self.n_estimators):
            if self.bootstrap:
                idx = rng.randint(0, n_samples, sample_size)
            else:
                idx = rng.choice(n_samples, sample_size, replace=False)
            tree = self._build_isolation_tree(X[idx], rng, max_depth=max_depth)
            self.estimators_.append(tree)
        self.sample_size_ = sample_size
        # Set offset for decision_function
        if self.contamination == 'auto':
            self.offset_ = -0.5
        else:
            scores = self.score_samples(X)
            self.offset_ = np.percentile(scores, 100.0 * self.contamination)
        return self

    def score_samples(self, X):
        """Return anomaly scores for samples. Lower = more anomalous."""
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        c_n = self._c(self.sample_size_)
        scores = np.empty(len(X))
        for i in range(len(X)):
            mean_path = np.mean([self._path_length(X[i], t)
                                 for t in self.estimators_])
            scores[i] = -np.power(2, -mean_path / max(c_n, 1e-15))
        return scores

    def decision_function(self, X):
        """Shifted anomaly scores: negative = outlier, positive = inlier."""
        return self.score_samples(X) - self.offset_

    def predict(self, X):
        """Return +1 for inliers, -1 for outliers."""
        decision = self.decision_function(X)
        result = np.ones(len(decision), dtype=int)
        result[decision < 0] = -1
        return result


# ---------------------------------------------------------------------------
# VotingClassifier
# ---------------------------------------------------------------------------
class VotingClassifier(BaseEstimator, ClassifierMixin):
    """Majority / weighted vote ensemble of heterogeneous classifiers."""

    def __init__(self, estimators, *, voting='hard', weights=None,
                 n_jobs=None, flatten_transform=True, verbose=False):
        self.estimators = estimators
        self.voting = voting
        self.weights = weights
        self.n_jobs = n_jobs
        self.flatten_transform = flatten_transform
        self.verbose = verbose
        self.estimators_ = []
        self.classes_ = None

    def fit(self, X, y):
        X, y = np.asarray(X, dtype=float), np.asarray(y)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        self.classes_ = np.unique(y)
        self.estimators_ = []
        for name, est in self.estimators:
            fitted = clone(est)
            fitted.fit(X, y)
            self.estimators_.append((name, fitted))
        return self

    def predict(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        predictions = np.array([est.predict(X)
                                for _, est in self.estimators_])
        weights = (np.array(self.weights, dtype=float)
                   if self.weights is not None
                   else np.ones(len(self.estimators_)))
        n_classes = len(self.classes_)
        class_votes = np.zeros((len(X), n_classes))
        for j, pred in enumerate(predictions):
            for k, c in enumerate(self.classes_):
                class_votes[:, k] += weights[j] * (pred == c)
        return self.classes_[np.argmax(class_votes, axis=1)]


# ---------------------------------------------------------------------------
# VotingRegressor
# ---------------------------------------------------------------------------
class VotingRegressor(BaseEstimator, RegressorMixin):
    """Weighted average ensemble of heterogeneous regressors."""

    def __init__(self, estimators, *, weights=None, n_jobs=None,
                 verbose=False):
        self.estimators = estimators
        self.weights = weights
        self.n_jobs = n_jobs
        self.verbose = verbose
        self.estimators_ = []

    def fit(self, X, y):
        X, y = np.asarray(X, dtype=float), np.asarray(y, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        self.estimators_ = []
        for name, est in self.estimators:
            fitted = clone(est)
            fitted.fit(X, y)
            self.estimators_.append((name, fitted))
        return self

    def predict(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        predictions = np.array([est.predict(X)
                                for _, est in self.estimators_])
        weights = (np.array(self.weights, dtype=float)
                   if self.weights is not None
                   else np.ones(len(self.estimators_)))
        weights = weights / weights.sum()
        return np.average(predictions, axis=0, weights=weights)


# ---------------------------------------------------------------------------
# StackingClassifier
# ---------------------------------------------------------------------------
class StackingClassifier(BaseEstimator, ClassifierMixin):
    """Stacked generalisation classifier.

    Fits base estimators, generates cross-validated predictions as meta
    features, then trains final_estimator on them.
    """

    def __init__(self, estimators, final_estimator=None, *, cv=5,
                 stack_method='auto', n_jobs=None, passthrough=False,
                 verbose=0):
        self.estimators = estimators
        self.final_estimator = final_estimator
        self.cv = cv
        self.stack_method = stack_method
        self.n_jobs = n_jobs
        self.passthrough = passthrough
        self.verbose = verbose
        self.estimators_ = []
        self.final_estimator_ = None
        self.classes_ = None

    def _get_final_estimator(self):
        if self.final_estimator is not None:
            return clone(self.final_estimator)
        from sklearn.linear_model import LogisticRegression
        return LogisticRegression()

    def fit(self, X, y):
        X, y = np.asarray(X, dtype=float), np.asarray(y)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        self.classes_ = np.unique(y)
        n_samples = X.shape[0]
        n_estimators = len(self.estimators)
        cv = self.cv if isinstance(self.cv, int) else 5

        # Cross-validated predictions for meta-features
        meta_features = np.zeros((n_samples, n_estimators))
        indices = np.arange(n_samples)
        fold_size = n_samples // cv
        self.estimators_ = []

        for est_idx, (name, est) in enumerate(self.estimators):
            for fold in range(cv):
                start = fold * fold_size
                end = start + fold_size if fold < cv - 1 else n_samples
                val_idx = indices[start:end]
                train_idx = np.concatenate([indices[:start], indices[end:]])
                est_clone = clone(est)
                est_clone.fit(X[train_idx], y[train_idx])
                pred = est_clone.predict(X[val_idx])
                # Encode predictions as numeric for the meta-learner
                if pred.dtype.kind in ('U', 'S', 'O'):
                    pred = np.searchsorted(self.classes_, pred).astype(float)
                meta_features[val_idx, est_idx] = pred.astype(float)

            # Re-fit on full data for final use at predict time
            full_est = clone(est)
            full_est.fit(X, y)
            self.estimators_.append((name, full_est))

        if self.passthrough:
            meta_features = np.hstack([meta_features, X])

        self.final_estimator_ = self._get_final_estimator()
        # Encode y for final estimator
        y_enc = y
        if y.dtype.kind in ('U', 'S', 'O'):
            y_enc = np.searchsorted(self.classes_, y)
        self.final_estimator_.fit(meta_features, y_enc)
        return self

    def predict(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        meta = np.zeros((len(X), len(self.estimators_)))
        for j, (_, est) in enumerate(self.estimators_):
            pred = est.predict(X)
            if pred.dtype.kind in ('U', 'S', 'O'):
                pred = np.searchsorted(self.classes_, pred).astype(float)
            meta[:, j] = pred.astype(float)
        if self.passthrough:
            meta = np.hstack([meta, X])
        final_pred = self.final_estimator_.predict(meta)
        if hasattr(final_pred, 'astype'):
            try:
                return self.classes_[final_pred.astype(int)]
            except (IndexError, ValueError):
                return final_pred
        return final_pred


# ---------------------------------------------------------------------------
# StackingRegressor
# ---------------------------------------------------------------------------
class StackingRegressor(BaseEstimator, RegressorMixin):
    """Stacked generalisation regressor.

    Fits base estimators, generates cross-validated predictions as meta
    features, then trains final_estimator on them.
    """

    def __init__(self, estimators, final_estimator=None, *, cv=5,
                 n_jobs=None, passthrough=False, verbose=0):
        self.estimators = estimators
        self.final_estimator = final_estimator
        self.cv = cv
        self.n_jobs = n_jobs
        self.passthrough = passthrough
        self.verbose = verbose
        self.estimators_ = []
        self.final_estimator_ = None

    def _get_final_estimator(self):
        if self.final_estimator is not None:
            return clone(self.final_estimator)
        from sklearn.linear_model import Ridge
        return Ridge()

    def fit(self, X, y):
        X, y = np.asarray(X, dtype=float), np.asarray(y, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        n_samples = X.shape[0]
        n_estimators = len(self.estimators)
        cv = self.cv if isinstance(self.cv, int) else 5

        meta_features = np.zeros((n_samples, n_estimators))
        indices = np.arange(n_samples)
        fold_size = n_samples // cv
        self.estimators_ = []

        for est_idx, (name, est) in enumerate(self.estimators):
            for fold in range(cv):
                start = fold * fold_size
                end = start + fold_size if fold < cv - 1 else n_samples
                val_idx = indices[start:end]
                train_idx = np.concatenate([indices[:start], indices[end:]])
                est_clone = clone(est)
                est_clone.fit(X[train_idx], y[train_idx])
                meta_features[val_idx, est_idx] = est_clone.predict(X[val_idx])

            full_est = clone(est)
            full_est.fit(X, y)
            self.estimators_.append((name, full_est))

        if self.passthrough:
            meta_features = np.hstack([meta_features, X])

        self.final_estimator_ = self._get_final_estimator()
        self.final_estimator_.fit(meta_features, y)
        return self

    def predict(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        meta = np.zeros((len(X), len(self.estimators_)))
        for j, (_, est) in enumerate(self.estimators_):
            meta[:, j] = est.predict(X)
        if self.passthrough:
            meta = np.hstack([meta, X])
        return self.final_estimator_.predict(meta)
